// WebSocket UI Plugin - Kernel Controlled
// Browser patches with deterministic WebSocket

// Initialize WebSocket connection
sandbox.ws.connect('ws://localhost:8080');

// Handle incoming WebSocket messages
sandbox.ws.onmessage = function(message) {
  const seed = sandbox.kernel.getState().seed;
  const tick = sandbox.time.tick();

  // Process message deterministically
  switch (message.type) {
    case 'patch_update':
      sandbox.handlePatchUpdate(message, seed, tick);
      break;
    case 'validation_result':
      sandbox.handleValidationResult(message, seed, tick);
      break;
    case 'kernel_state':
      sandbox.handleKernelState(message, seed, tick);
      break;
  }

  sandbox.kernel.logEvent({
    type: 'websocket_message_processed',
    message: message,
    tick: tick,
    seed: seed
  });
};

// Handle tick events with WebSocket sync
sandbox.onTick = function(eventData) {
  const tick = sandbox.time.tick();
  const seed = sandbox.kernel.getState().seed;

  // Send tick state via WebSocket
  if (tick % 5 === 0) { // Every 5 ticks
    sandbox.ws.send({
      type: 'ui_tick_update',
      tick: tick,
      seed: seed,
      resources: sandbox.state.get('resources') || {},
      structures: sandbox.state.get('structures') || []
    });
  }
};

// Handle events with WebSocket broadcasting
sandbox.onEvent = function(eventType, eventData) {
  const seed = sandbox.kernel.getState().seed;
  const tick = sandbox.time.tick();

  // Broadcast important events
  if (['structurePlaced', 'patchApplied', 'validationError'].includes(eventType)) {
    sandbox.ws.send({
      type: 'ui_event',
      eventType: eventType,
      eventData: eventData,
      tick: tick,
      seed: seed
    });
  }
};

// Handle patch updates
sandbox.handlePatchUpdate = function(message, seed, tick) {
  // Update patch list deterministically
  const patches = message.patches || [];
  sandbox.state.set('patches', patches);

  // Update UI with deterministic sorting
  const sortedPatches = patches.sort((a, b) => {
    const hashA = sandbox.rng.randint(0, 1000) + a.id.charCodeAt(0);
    const hashB = sandbox.rng.randint(0, 1000) + b.id.charCodeAt(0);
    return hashA - hashB;
  });

  // Update patch list UI
  const patchListElement = document.querySelector('.patch-list');
  if (patchListElement) {
    sandbox.ui.updateElement(patchListElement, {
      innerHTML: sortedPatches.map(patch => `
        <div class="patch-item" data-patch-id="${patch.id}">
          <div class="patch-info">
            <span class="patch-name">${patch.id}</span>
            <span class="patch-version">v${patch.version}</span>
          </div>
          <div class="patch-actions">
            <button class="patch-action-btn" onclick="togglePatch('${patch.id}')">
              ${patch.enabled ? 'Disable' : 'Enable'}
            </button>
          </div>
        </div>
      `).join('')
    });
  }
};

// Handle validation results
sandbox.handleValidationResult = function(message, seed, tick) {
  const result = message.result || {};

  // Update validation output
  const outputElement = document.querySelector('.validation-output');
  if (outputElement) {
    const messageClass = result.valid ? 'success' : 'error';
    const messageText = result.valid 
      ? 'Validation passed successfully' 
      : `Validation failed: ${result.errors?.join(', ') || 'Unknown error'}`;

    const messageElement = sandbox.ui.createElement('div', {
      className: `console-line ${messageClass}`,
      textContent: `[${tick}] ${messageText}`
    });

    outputElement.appendChild(messageElement);
    outputElement.scrollTop = outputElement.scrollHeight;
  }
};

// Handle kernel state updates
sandbox.handleKernelState = function(message, seed, tick) {
  const state = message.state || {};

  // Update UI state deterministically
  sandbox.state.set('kernelState', state);

  // Update resource displays
  if (state.resources) {
    const oreElement = document.querySelector('#oreCount');
    const ironElement = document.querySelector('#ironCount');

    if (oreElement) {
      sandbox.ui.updateElement(oreElement, {
        textContent: state.resources.ore || 0
      });
    }

    if (ironElement) {
      sandbox.ui.updateElement(ironElement, {
        textContent: state.resources.iron || 0
      });
    }
  }

  // Update tick display
  const tickElement = document.querySelector('#tickCount');
  if (tickElement) {
    sandbox.ui.updateElement(tickElement, {
      textContent: state.tick || tick
    });
  }
};

// Connection established
sandbox.onConnect = function() {
  console.log('[PLUGIN] WebSocket connected through kernel');

  // Send initial state
  sandbox.ws.send({
    type: 'plugin_connected',
    pluginId: 'websocket-ui-plugin',
    seed: sandbox.kernel.getState().seed,
    tick: sandbox.time.tick()
  });
};
